r()                                                        // Toggle the list visibility directly via a Binding                            Toggle("", isOn: Binding(                                get: { list.isVisible },                                set: { _ in                                    withAnimation {                                        viewModel.toggleVisibility(for: list)                                    }                                }                            ))                            .labelsHidden()                        }                        .contentShape(Rectangle()) // entire row is tappable                        .contextMenu {                            Button(role: .destructive) {                                listToDelete = list                                showDeleteConfirmation = true                            } label: {                                Label("Delete", systemImage: "trash")                            }                        }                    }                    .onDelete { indexSet in                        if let first = indexSet.first {                            let list = viewModel.allLists.lists[first]                            listToDelete = list                            showDeleteConfirmation = true                        }                    }                    .onMove { source, destination in                        // Reorder in ViewModel                        viewModel.moveList(from: source, to: destination)                    }                }                .listStyle(PlainListStyle())                // (Optional) help SwiftUI animate reordering and deletions more smoothly:                .animation(.default, value: viewModel.allLists.lists)                                HStack {                    Button(action: {                        showAddListSheet = true                    }) {                        HStack {                            Image(systemName: "plus")                            Text("Add List")                        }                    }                    Spacer()                    EditButton()                }                .padding([.horizontal, .bottom])            }            .frame(maxWidth: 350, maxHeight: 500)            .background(Color(UIColor.systemBackground))            .cornerRadius(16)            .shadow(radius: 10)            .padding()        }        // Delete Confirmation Alert        .alert(isPresented: $showDeleteConfirmation) {            Alert(                title: Text("Delete List"),                message: Text("Are you sure you want to delete \"\(listToDelete?.title ?? "this list")\"?"),                primaryButton: .destructive(Text("Delete")) {                    if let list = listToDelete,                       let index = viewModel.allLists.lists.firstIndex(where: { $0.id == list.id }) {                        viewModel.removeList(at: index)                    }                },                secondaryButton: .cancel()            )        }                // Add List Sheet        .sheet(isPresented: $showAddListSheet) {            NavigationView {                VStack {                    TextField("List Title", text: $newListTitle)                        .textFieldStyle(RoundedBorderTextFieldStyle())                        .padding()                                        Spacer()                }                .navigationBarTitle("New List", displayMode: .inline)                .navigationBarItems(                    leading: Button("Cancel") {                        showAddListSheet = false                        newListTitle = ""                    },                    trailing: Button("Add") {                        let trimmedTitle = newListTitle.trimmingCharacters(in: .whitespaces)                        if !trimmedTitle.isEmpty {                            viewModel.addList(title: trimmedTitle)                            showAddListSheet = false                            newListTitle = ""                        }                    }                    .disabled(newListTitle.trimmingCharacters(in: .whitespaces).isEmpty)                )            }        }                // Rename List Sheet        .sheet(isPresented: $showRenameSheet) {            NavigationView {                VStack {                    TextField("List Title", text: $renameTitle)                        .textFieldStyle(RoundedBorderTextFieldStyle())                        .padding()                                        Spacer()                }                .navigationBarTitle("Rename List", displayMode: .inline)                .navigationBarItems(                    leading: Button("Cancel") {                        showRenameSheet = false                        renameTitle = ""                    },                    trailing: Button("Save") {                        let trimmedTitle = renameTitle.trimmingCharacters(in: .whitespaces)                        if                            !trimmedTitle.isEmpty,                            let list = listToRename,                            let index = viewModel.allLists.lists.firstIndex(where: { $0.id == list.id })                        {                            viewModel.allLists.lists[index].title = trimmedTitle                        }                        showRenameSheet = false                        renameTitle = ""                    }                    .disabled(renameTitle.trimmingCharacters(in: .whitespaces).isEmpty)                )            }        }    }}